// Watteco → Vlegel IoT Hub formatter
// Output 1 = pulses (Id 2000)
// Output 2 = battery (Id 7200)

let mid = global.get("mid") || 0;

// Stel de constante Dev in (start met 36)
const Dev = "ASSET_ID_START_MET_36";

// Stel de pulse omvormings waarde in
const PulseConversionValue = 1;
const PulseDataTypeId = 5600;

if (typeof PulseConversionValue !== "number" || !Number.isFinite(PulseConversionValue)) {
    node.error("PulseConversionValue must be a finite number.", msg);
    return [null, null];
}
if (typeof PulseDataTypeId !== "number" || !Number.isInteger(PulseDataTypeId) || PulseDataTypeId <= 0) {
    node.error("PulseConvertedId must be a positive integer.", msg);
    return [null, null];
}

// -------- helpers --------
function u16(bytes, i) {
    return (bytes[i] << 8) | bytes[i + 1];
}
function u32(bytes, i) {
    return ((bytes[i] << 24) >>> 0) |
        (bytes[i + 1] << 16) |
        (bytes[i + 2] << 8) |
        bytes[i + 3];
}

function buildResult(ts) {
    return {
        MID: mid,
        D: [{
            Dev: Dev,
            TS: ts,
            ED: [],
            MD: []
        }]
    };
}

function addRadioMeta(result, msg) {
    if (msg.snr !== undefined)
        result.D[0].MD.push({ Id: 5400, Val: parseFloat(msg.snr) });
    if (msg.rssi !== undefined)
        result.D[0].MD.push({ Id: 5500, Val: parseFloat(msg.rssi) });
    if (msg.dr && msg.dr.spreadFactor !== undefined)
        result.D[0].MD.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });
}

// -------- payload extract --------
const meta = (typeof msg.payload === "object" && msg.payload) ? msg.payload : {};
const b64 =
    (meta && typeof meta.payload === "string" && meta.payload) ||
    (typeof msg.payload === "string" ? msg.payload : null) ||
    (meta && meta.payload && typeof meta.payload.payload === "string" ? meta.payload.payload : null);

if (!b64) {
    node.error("No base64 payload found", msg);
    return [null, null];
}

const bytes = Buffer.from(b64, "base64");

// timestamp
const TS = (msg.time ? new Date(msg.time) : new Date()).toISOString();

// Watteco frame
const cmd = bytes[1];
const cluster = u16(bytes, 2);
const attr = u16(bytes, 4);

// Only handle REPORT (0x0A)
if (cmd !== 0x0a) return [null, null];


// ======================
// 1️⃣ PULSE COUNTER
// cluster 0x000f, attr 0x0402
// ======================
if (cluster === 0x000f && attr === 0x0402) {
    const pulse_counter = u32(bytes, 7);

    const result = buildResult(TS);

    result.D[0].MD.push({
        Id: PulseDataTypeId,
        Val: pulse_counter * PulseConversionValue
    });

    addRadioMeta(result, msg);

    global.set("mid", mid + 1);
    msg.payload = result;
    return [msg, null];
}


// ======================
// 2️⃣ BATTERY
// cluster 0x0050, attr 0x0006
// ======================
if (cluster === 0x0050 && attr === 0x0006) {
    const rr = bytes[9]; // power source mask
    let idx = 10;

    const sources = [0x01, 0x02, 0x04, 0x08, 0x10];
    let disposable_mv = null;

    for (const bit of sources) {
        if (rr & bit) {
            const mv = u16(bytes, idx);
            if (bit === 0x04) disposable_mv = mv; // disposable battery
            idx += 2;
        }
    }

    const result = buildResult(TS);

    if (disposable_mv != null) {
        result.D[0].MD.push({
            Id: 7200, // battery
            Val: Math.round((disposable_mv / 1000) * 1000) / 1000 // V
        });
    }

    addRadioMeta(result, msg);

    global.set("mid", mid + 1);
    msg.payload = result;
    return [null, msg];
}

// ======================
return [null, null];
